using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// Use the default options (includes the default reflection-based resolver).
var options = JsonSerializerOptions.Default;

// 1) Strongly-typed metadata retrieval — returns JsonTypeInfo<T> directly.
JsonTypeInfo<int[]> arrayMeta = options.GetTypeInfo<int[]>();
Console.WriteLine($"Got typed metadata: {arrayMeta.Type.Name}[] — kind = {arrayMeta.Kind}");

// 2) Probe without throwing — TryGetTypeInfo returns false instead of throwing.
if (options.TryGetTypeInfo(typeof(string), out JsonTypeInfo? stringMeta))
{
    Console.WriteLine($"string metadata available: kind = {stringMeta!.Kind}");
}
else
{
    Console.WriteLine("string metadata NOT available");
}

// Demonstrate the "not available" path using options with no resolver.
var empty = new JsonSerializerOptions { TypeInfoResolver = null };
empty.MakeReadOnly();          // must be frozen before querying

if (empty.TryGetTypeInfo(typeof(string), out JsonTypeInfo? missing))
{
    Console.WriteLine($"Unexpected: got metadata from empty options");
}
else
{
    Console.WriteLine("As expected: no metadata for string in resolver-less options");
}

